const results = $json.results || [];
const restaurants = results.map(place => ({
  place_id: place.place_id,
  name: place.name,
  address: place.vicinity,
  rating: place.rating || 0,
  review_count: place.user_ratings_total || 0,
  types: place.types?.join(', ') || '',
  lat: place.geometry?.location?.lat,
  lng: place.geometry?.location?.lng
}));
return restaurants.map(r => ({ json: r }));

const detail = $json.result || {};
const restaurant = $input.first().json;
return [{ json: {
  ...restaurant,
  website: detail.website || '',
  phone: detail.formatted_phone_number || ''
} }];

const restaurant = $input.first().json;
const html = $json.data || '';
const htmlLower = html.toLowerCase();

const hasOrderOnline = /order.*online|online.*order|order.*now/i.test(htmlLower);
const hasDoordash = /doordash|door dash/i.test(htmlLower);
const hasUbereats = /uber\s*eats|ubereats/i.test(htmlLower);
const hasGrubhub = /grubhub|grub hub/i.test(htmlLower);
const hasSquare = /square|squareup/i.test(htmlLower);
const hasToast = /toasttab|toast/i.test(htmlLower);
const hasChownow = /chownow|chow now/i.test(htmlLower);

let score = 0;
let reasons = [];

if (restaurant.website) {
  score += 1;
  reasons.push('has_website');
}

if (!hasOrderOnline) {
  score += 2;
  reasons.push('no_online_ordering');
}

if (hasDoordash || hasUbereats || hasGrubhub) {
  score += 1;
  reasons.push('on_third_party_platforms');
}

if (restaurant.rating >= 3.5) {
  score += 1;
  reasons.push('good_rating');
}

if (restaurant.phone) {
  score += 1;
  reasons.push('has_phone');
}

let category = 'Skip';
if (score >= 4) category = 'Qualified';
else if (score >= 2) category = 'Research';

return [{ json: {
  ...restaurant,
  website_analysis: {
    has_order_online: hasOrderOnline,
    has_doordash: hasDoordash,
    has_ubereats: hasUbereats,
    has_grubhub: hasGrubhub,
    has_square: hasSquare,
    has_toast: hasToast,
    has_chownow: hasChownow
  },
  score,
  score_reasons: reasons,
  category,
  stage: 'New',
  owner: 'Green',
  created_date: new Date().toISOString(),
  source: 'google_maps_scraper'
} }];
